#include<stdio.h>
int main()
{
  int n,a,x,b,y;
  scanf("%d %d %d %d %d",&n,&a,&x,&b,&y);
  while(1)
  {
    if(a==b)
    {
      printf("YES\n");
      return 0;
    }
    if(a==x || b==y)
      break;
    if(a==n-1)
      a=n;
    else
      a=(a+1)%n;
    if(b==1)
      b=n;
    else
      b=(b-1+n)%n;
  }
  printf("NO");
}

