use std::io;
fn main(){
    let mut line=String::new();
    io::stdin().read_line(&mut line).expect("Die");
    let arr:Vec<i32> = line.split(" ").map(|x| x.trim().parse().expect("Int")).collect();
    let (mut i,mut j):(i32,i32)=(arr[1],arr[3]);
    let mut ans=false;
    loop{
        i+=1;
        if i>arr[0]{
            i=1;
        }

        j-=1;
        if j<=0{
            j=arr[0];
        }
        if i==j{
            ans=true;
            break;
        }
        else if i==arr[2] || j==arr[4]{
            break;
        }
    }

    if ans{
        println!("YES")
    }
    else{
        println!("NO")
    }
}
